import { test, expect } from '@playwright/test';
import path from 'path';
import { fileURLToPath } from 'url';
const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
test('should heal inside an iframe', async ({
  page
}) => {
  const loginUrl = `file://${path.resolve(__dirname, 'target-app', 'iframe_outer.html')}`;
  await page.goto(loginUrl);

  // This locator uses an ID that will "change" in our next step
  const payButton = page.frameLocator('#payment-frame').getByRole('button', {
    name: 'Submit Payment'
  });
  await expect(payButton).toBeVisible();
  await payButton.click();
});
